<?php
include 'config.php';
include 'questions.php';

header('Content-Type: application/json');

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $action = $_POST['action'] ?? '';
    
    if ($action === 'calculate_results') {
        $module = intval($_POST['module'] ?? 0);
        $responses_json = $_POST['responses'] ?? '{}';
        $responses = json_decode($responses_json, true);
        
        if (json_last_error() !== JSON_ERROR_NONE) {
            echo json_encode([
                'success' => false, 
                'message' => 'Ошибка декодирования JSON: ' . json_last_error_msg()
            ]);
            exit;
        }
        
        if ($module === 1) {
            $results = calculateModule1Results($responses);
        } elseif ($module === 2) {
            $results = calculateModule2Results($responses);
        } elseif ($module === 3) {
            $results = calculateModule3Results($responses);
        } elseif ($module === 4) {
            $results = calculateModule4Results($responses);
        } else {
            echo json_encode(['success' => false, 'message' => 'Неверный модуль']);
            exit;
        }
        
        // Преобразуем ответы в формат без null перед сохранением
        $clean_responses = [];
        foreach ($responses as $key => $value) {
            if (is_numeric($key) && $value !== null) {
                $clean_responses[intval($key)] = $value;
            }
        }
        
        // Сохраняем результаты в файл
        $save_data = [
            'survey_id' => $_SESSION['survey_id'],
            'module' => $module,
            'timestamp' => date('Y-m-d H:i:s'),
            'total_questions' => count(getQuestions($module)),
            'answered_questions' => count($clean_responses),
            'responses' => $clean_responses,
            'results' => $results,
            'ip_address' => $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ];
        
        $filename = 'results/module_' . $module . '_' . $_SESSION['survey_id'] . '_' . date('Ymd_His') . '.json';
        $result = file_put_contents($filename, json_encode($save_data, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE));
        
        if ($result !== false) {
            $_SESSION['responses'][$module] = [];
            
            echo json_encode([
                'success' => true,
                'message' => 'Результаты успешно сохранены',
                'filename' => basename($filename),
                'results' => $results
            ]);
        } else {
            echo json_encode([
                'success' => false,
                'message' => 'Ошибка при сохранении файла'
            ]);
        }
    }
    elseif ($action === 'retake_module') {
        $module = intval($_POST['module'] ?? 0);
        
        if ($module >= 1 && $module <= 4) {
            $_SESSION['responses'][$module] = [];
            
            echo json_encode([
                'success' => true,
                'message' => 'Модуль ' . $module . ' можно пройти заново.',
                'deleted_files' => 0
            ]);
        } else {
            echo json_encode([
                'success' => false,
                'message' => 'Неверный номер модуля'
            ]);
        }
    }
}

// ==================== ПОЛНЫЕ ИНТЕРПРЕТАЦИИ ДЛЯ МОДУЛЯ 1 ====================

function calculateModule1Results($responses) {
    global $module1_keys;
    $results = [];
    
    // Шкала лжи (L)
    $lie_raw_score = 0;
    if (isset($module1_keys['lie']['true'])) {
        foreach ($module1_keys['lie']['true'] as $q) {
            if (isset($responses[$q]) && $responses[$q] === 'true') {
                $lie_raw_score++;
            }
        }
    }
    if (isset($module1_keys['lie']['false'])) {
        foreach ($module1_keys['lie']['false'] as $q) {
            if (isset($responses[$q]) && $responses[$q] === 'false') {
                $lie_raw_score++;
            }
        }
    }
    $results['lie_raw_score'] = $lie_raw_score;
    $lie_index = round($lie_raw_score / 11, 2);
    $results['lie_index'] = $lie_index;
    
    if ($lie_index < 0.6) {
        $results['lie_interpretation'] = 'Результаты можно считать относительно достоверными.';
    } else {
        $results['lie_interpretation'] = 'Наблюдается тенденция к искажению действительности в сторону самопрезентации и неадекватности ответов.';
    }
    
    // Основные шкалы
    $scales = [
        'psychosomatic' => 'Психосоматические риски',
        'anxiety' => 'Тревога',
        'demonstrative' => 'Демонстративность',
        'frustration' => 'Фрустрационные установки',
        'sensitivity' => 'Сензитивность',
        'distancing' => 'Дистанцирование',
        'hypomania' => 'Гипомания',
        'extraversion' => 'Экстраверсия-Интроверсия',
        'emotional_intelligence' => 'Эмоциональный интеллект'
    ];
    
    foreach ($scales as $scale => $name) {
        $score = 0;
        if (isset($module1_keys[$scale]['true'])) {
            foreach ($module1_keys[$scale]['true'] as $q) {
                if (isset($responses[$q]) && $responses[$q] === 'true') {
                    $score++;
                }
            }
        }
        if (isset($module1_keys[$scale]['false'])) {
            foreach ($module1_keys[$scale]['false'] as $q) {
                if (isset($responses[$q]) && $responses[$q] === 'false') {
                    $score++;
                }
            }
        }
        $results[$scale] = $score;
        $results[$scale . '_interpretation'] = getScaleInterpretation($scale, $score);
    }
    
    // Суицидальная шкала
    $suicidal_score = 0;
    if (isset($module1_keys['suicidal']['true'])) {
        foreach ($module1_keys['suicidal']['true'] as $q) {
            if (isset($responses[$q]) && $responses[$q] === 'true') {
                $suicidal_score++;
            }
        }
    }
    if (isset($module1_keys['suicidal']['false'])) {
        foreach ($module1_keys['suicidal']['false'] as $q) {
            if (isset($responses[$q]) && $responses[$q] === 'false') {
                $suicidal_score++;
            }
        }
    }
    $suicidal_percent = round(($suicidal_score / 35) * 100);
    $results['suicidal'] = $suicidal_percent;
    
    // Интерпретация суицидальной шкалы (ПОЛНАЯ ВЕРСИЯ ИЗ ДОКУМЕНТА)
    if ($suicidal_percent <= 20) {
        $results['suicidal_interpretation'] = 'Анализ психологического профиля личности с низким уровнем склонности к суицидальному поведению требует понимания системы внутренних и внешних факторов, которые формируют так называемую «психологическую устойчивость» или антисуицидальный барьер. В личной истории таких людей часто прослеживается успешный опыт преодоления прошлых кризисов. Они знают, что «это проходит», так как уже имеют эмпирическое подтверждение своей способности справляться. В их лексиконе преобладают жизнеутверждающие установки, а в поведении отсутствует паттерн «рискованного самовыражения» (экстремальное поведение без страховки, злоупотребление ПАВ). Низкий уровень склонности не означает полной неуязвимости. Это динамический показатель. Однако при текущей конфигурации личностных черт и внешних обстоятельств, психологический иммунитет человека оценивается как стабильный и высокий. Низкий показатель по данной шкале — это не просто отсутствие деструктивных мыслей, а наличие развитых адаптивных механизмов.';
    } elseif ($suicidal_percent <= 40) {
        $results['suicidal_interpretation'] = 'Проявление склонности к суицидальному поведению возможна лишь при длительном стрессе и сильных эмоциональных потрясениях. Склонность к суицидальному поведению крайне редко возникает «на пустом месте» у человека, находящегося в ресурсном состоянии и имеющего стабильную опору. Это всегда комплексный процесс, где длительный стресс выступает как эрозия почвы, а сильное потрясение — как оползень. Понимание этой динамики критически важно для профилактики: коррекция состояния на этапе «просто стресса» и восстановление психологических ресурсов способны предотвратить трагическую развязку даже при наступлении крайне тяжелых жизненных событий.';
    } elseif ($suicidal_percent <= 60) {
        $results['suicidal_interpretation'] = 'Проявление склонности к суицидальному поведению носит ситуационный характер. Согласно этому критическое состояние человека не является постоянной чертой его личности, а становится следствием временной комбинации внешних факторов и внутреннего истощения ресурсов. Суицидальный кризис в этом контексте рассматривается не как логическое завершение жизненного пути, а как временная неспособность психики справиться с конкретной ситуацией. Даже в момент самого острого ситуационного кризиса человек почти всегда сохраняет амбивалентность — одновременное желание прекратить боль и желание жить. Ситуативность проявляется в том, что совершающий действие ищет не смерти, а способа остановить невыносимые обстоятельства. Если показать другой способ остановки боли, суицидальный импульс угасает. Признание ситуативности суицидального поведения — это основа экстренной психологической помощи. Это означает, что: состояние обратимо; кризис ограничен во времени. Изменение внешней среды или предоставление временной опоры (безопасного пространства, выслушивания) эффективно предотвращает трагедию.';
    } elseif ($suicidal_percent <= 80) {
        $results['suicidal_interpretation'] = 'ГРУППА РИСКА: Высока вероятность проявления суицидального поведения. Высокая вероятность суицидального поведения чаще всего коррелирует с исчерпанием внутреннего ресурса сопротивляемости (копинга). Когда жизненные обстоятельства (конфликты, потери, хронический стресс) превышают порог психической выносливости, психика ищет способ «сбросить» невыносимое напряжение. В трудных или напряженных жизненных ситуациях у них может развиться аутоагрессия, т.е. причинять себе вред в физической или психической сфере. Она может носить скрытый или явный характер. Аутоагрессия в данном контексте выступает как эрзац-регуляция. Если человек не может изменить внешнюю ситуацию или справиться с душевной болью, он перенаправляет гнев и деструктивную энергию на самого себя. Критическим признаком является так называемое «туннельное сознание», когда человек перестает видеть альтернативные выходы из ситуации, кроме радикальных. Самопомощь или «дружеские беседы» на этом этапе часто оказываются неэффективными, а иногда и опасными, так как могут усилить чувство непонятости. Такое состояние требует не оценки силы воли, а системного медицинского и психологического протокола лечения. Своевременное обращение к специалисту (клиническому психологу, психотерапевту или психиатру) является единственным надежным способом предотвратить трагедию и вернуть человеку способность видеть жизненные перспективы.';
    } else {
        $results['suicidal_interpretation'] = 'КРАЙНЕ ВЫСОКИЙ УРОВЕНЬ склонности к суицидальному поведению. Когда речь идет о крайне высоком уровне суицидального риска, ситуация переходит из области «психологических трудностей» в область медицинской экстренности. В таком состоянии психика человека находится в режиме терминального кризиса, где инстинкт самосохранения подавлен интенсивной душевной болью, которую мозг воспринимает как невыносимую физическую пытку. Критический уровень риска — это состояние, которое поддается лечению. Но первым шагом к спасению всегда является передача ответственности за жизнь человека в руки подготовленных медицинских специалистов.';
    }
    
    return $results;
}

