// ==================== ПОЛНЫЕ ИНТЕРПРЕТАЦИИ ДЛЯ МОДУЛЯ 2 ====================

function calculateModule2Results($responses) {
    $results = [];
    
    // Часть 1
    $part1 = [
        'emotional' => 0,
        'cognitive' => 0,
        'physical' => 0,
        'behavioral' => 0
    ];
    
    $part1_total = 0;
    for ($i = 1; $i <= 60; $i++) {
        if (isset($responses[$i])) {
            $score = intval($responses[$i]);
            $part1_total += $score;
            if ($i <= 15) $part1['emotional'] += $score;
            elseif ($i <= 30) $part1['cognitive'] += $score;
            elseif ($i <= 45) $part1['physical'] += $score;
            else $part1['behavioral'] += $score;
        }
    }
    
    $results['part1'] = $part1;
    $results['part1']['total'] = $part1_total;
    
    $results['part1']['emotional_interpretation'] = getBlockInterpretation('emotional', $part1['emotional']);
    $results['part1']['cognitive_interpretation'] = getBlockInterpretation('cognitive', $part1['cognitive']);
    $results['part1']['physical_interpretation'] = getBlockInterpretation('physical', $part1['physical']);
    $results['part1']['behavioral_interpretation'] = getBlockInterpretation('behavioral', $part1['behavioral']);
    $results['part1']['total_interpretation'] = getTotalInterpretation($part1_total);
    
    // Часть 2
    $part2_score = 0;
    for ($i = 61; $i <= 95; $i++) {
        if (isset($responses[$i])) {
            $answer = intval($responses[$i]);
            if ($i <= 70) {
                $part2_score += (6 - $answer);
            } else {
                $part2_score += $answer;
            }
        }
    }
    
    $results['part2'] = $part2_score;
    
    if ($part2_score <= 96) {
        $results['part2_interpretation'] = 'Адаптивный вариант поведения и деятельности. Поздравляем, у вас хороший уровень адаптации. Ваш результат указывает на состояние, которое в психологии называют посттравматическим ростом или высокой жизнестойкостью. Речь идет о ситуации, когда человек прошел через серьезное испытание, но его психика смогла интегрировать этот опыт, не позволив ему стать центральной осью, вокруг которой вращается вся жизнь. Условная норма не означает «выздоровление» в медицинском смысле, так как травма — это не болезнь, а событие. В вашем случае воспоминания о пережитом хранятся в памяти как часть личной истории, а не как открытая рана. Вы осознаете, что «это было», но это событие больше не обладает властью диктовать вам, как себя чувствовать сегодня. Ваша психика переработала хаос в опыт. Ваша нервная система тоже работает в адаптивном режиме. Вы можете думать о прошлом, когда это необходимо, но мысли не вторгаются в ваше сознание насильно (отсутствие деструктивных интрузий). Вы не живете в состоянии постоянной «боевой готовности». Ваше «окно толерантности» достаточно широко, чтобы выдерживать стресс, не впадая в панику или оцепенение. Страх, возникший в момент травмы, не распространился на все сферы жизни. Если травма была связана с конкретным местом или человеком, это не заставило вас бояться всего мира. Одним из главных последствий тяжелого опыта является разрушение базовых убеждений (например, «мир безопасен», «я имею ценность»). Ваш балл говорит о том, что эти опоры устояли или были успешно восстановлены. Вы сохраняете способность доверять — и себе, и окружающим. Способность строить близкие отношения — это самый точный маркер психологического здоровья, так как именно близость требует наибольшей уязвимости, которую травмированный человек обычно не может себе позволить. Вы не застряли в поиске ответа на вопрос «За что это мне?». Вместо этого вы живете в парадигме «Что я делаю теперь?». Ваше будущее не заблокировано прошлым; у вас есть планы, цели и желания, которые не связаны с компенсацией пережитого ужаса. Ваше состояние — это результат большой внутренней работы, осознанной или бессознательной. Главная задача сейчас — сохранять этот баланс и позволять себе жить полной жизнью, не оглядываясь на тени прошлого. Полезно обсуждать свой опыт в безопасной среде (с психологом), чтобы убедиться, что накопленное напряжение не превращается в «архив», который когда-нибудь может переполниться. Психолог обучит методам управления стрессом (медитация, дыхательные упражнения, техники релаксации), поможет развить навыки эмоциональной саморегуляции, научит справляться с болезненными переживаниями.';
    } elseif ($part2_score >= 97 && $part2_score <= 111) {
        $results['part2_interpretation'] = 'Вы испытываете проблемы с адаптацией к обычной жизни. Будьте внимательны, вы испытываете значительные и устойчивые проблемы с адаптацией к обычной жизни. Ваши баллы указывают на состояние, при котором масштаб внутренних переживаний начинает превосходить способность психики с ними справляться. Когда травматический опыт не «переваривается» вовремя, он кристаллизуется и начинает диктовать свои правила, постепенно перекраивая личность и образ жизни человека. Одной из самых тяжелых черт этого состояния является эмоциональная скудость. Ваша психика, чтобы защитить себя от невыносимой боли, «выключает» чувствительность, и вы начинаете чувствовать себя словно за толстым стеклом: видите мир, но не ощущаете его тепла. Вам становится трудно сопереживать даже самым близким. Радость других кажется чужой и непонятной, а их проблемы — пустяковыми. Начинают появляться навязчивые мысли о том, что «можно было поступить иначе» или что «я теперь какой-то не такой». Эти чувства токсичны и заставляют вас закрываться еще сильнее. Из-за внутренней напряженности общение становится энергозатратным. Вы ощущаете постоянное чувство угрозы, которое приводит к тому, что любая мелочь вызывает вспышку гнева или раздражения. Близкие чувствуют вашу непредсказуемость и начинают «ходить на цыпочках», что только увеличивает дистанцию. Ваше тело находится в состоянии «красной угрозы». Сердцебиение, холодный пот, тремор при малейшем напоминании о событии. Проблемы со сном — это результат того, что мозг боится «отключить контроль». Чтобы не сталкиваться с болью, вы начинаете сужать свою жизнь, ограничивая жизнь пределами квартиры или дома. Будьте осторожны, алкоголь или психоактивные вещества часто используются как «анестезия». Они дают временное облегчение, глушат флешбэки, но на самом деле блокируют естественную способность мозга к восстановлению, усугубляя депрессию. Ваше состояние — это порог. Психика уже подала все возможные сигналы SOS. Самостоятельно «взять себя в руки» здесь практически невозможно, так как те механизмы, которыми человек обычно пользуется (воля, логика, самоанализ), сами повреждены травмой. Этот результат является прямым показанием для начала курса психотерапии, специализированного на работе с психологической травмой. Обращение к психологу или психотерапевту на этом этапе является наиболее эффективным способом предотвратить углубление состояния и переход в зону ПТСР.';
    } else {
        $results['part2_interpretation'] = 'ПТСР и рекомендуется пройти курс реабилитации. Результат отражает степень выраженности посттравматической симптоматики и сложностей адаптации на момент тестирования. Более высокий балл указывает на большую интенсивность переживаний и нарушений. Внимание, опасность! Ваша симптоматика подтверждают наличие посттравматического стрессового расстройства, при котором психика оказывается «запертой» в моменте травматического события. Это состояние выходит далеко за рамки обычного стресса, становясь тотальным фильтром, через который воспринимается вся окружающая реальность. Главная характеристика ПТСР — отсутствие временной дистанции между прошлым и настоящим. Травматический опыт не переходит в категорию «воспоминаний», он остается активным процессом. Личность претерпевает глубокую трансформацию: меняются базовые убеждения о безопасности мира и собственной ценности. Это ведет к дезадаптации, когда привычные социальные роли (в семье, работе, дружбе) становятся невыполнимыми из-за колоссальных внутренних затрат на поддержание психического равновесия. Человек может страдать от неконтролируемых рецидивирующих воспоминаний (флешбэков) и пугающих сновидений, что провоцирует состояние постоянного психоэмоционального напряжения и ведет к нервному истощению. Характерно защитное избегание любых стимулов, ассоциирующихся с пережитым ужасом. Чтобы спастись от боли, психика включает механизмы «заморозки». Это проявляется как алекситимия — неспособность распознавать и проживать чувства. Вы не можете чувствовать любовь или радость и это форма защитной анестезии, которая в итоге приводит к социальной изоляции. Часто формируются искаженные когнитивные установки о собственной вине или фатальной несправедливости устройства общества. У вас возникают устойчивые идеи вины («я должен был сделать иначе»), стыда или убеждение, что мир тотально несправедлив. Эти мысли становятся фундаментом для развития тяжелой депрессии. ПТСР часто сопровождается аутоагрессией. Не имея возможности справиться с внутренним напряжением, человек может прибегать к самоповреждению или опасному поведению. Злоупотребление психоактивными веществами (алкоголем, препаратами) в данном контексте часто является попыткой «самолечения» — стремлением заглушить невыносимую тревогу или выключить поток кошмаров. В критических точках это может приводить к формированию суицидальных намерений. Необходима комплексная и систематическая медицинская и психологическая поддержка. Ключевую роль играет вмешательство психотерапевта или психиатра для решения вопроса о медикаментозной коррекции (подбор антидепрессантов и анксиолитиков) на фоне интенсивной психотерапевтической работы. Процесс восстановления должен носить многоуровневый характер и может реализовываться как в условиях стационара, так и амбулаторно. Квалифицированное лечение позволяет минимизировать деструктивное влияние травмы, вернуть субъективное ощущение безопасности и восстановить ценность жизни. После стационарного лечения необходима работа с психологом, который  предложит вам индивидуальную программу психологического сопровождения.';
    }
    
    return $results;
}

