function generateModule3Recommendations($results) {
    $recommendations = [];
    
    $max_score = -1;
    $top_profiles = [];
    
    foreach ($results as $profile => $score) {
        if ($profile != 'recommendations' && !str_ends_with($profile, '_interpretation') && is_numeric($score)) {
            if ($score > $max_score) {
                $max_score = $score;
                $top_profiles = [$profile];
            } elseif ($score == $max_score && $max_score > 0) {
                $top_profiles[] = $profile;
            }
        }
    }
    
    $recommendations[] = "Важно! Результаты теста — это отправная точка. Чтобы они стали стратегией, их нужно пропустить через фильтр реальности: востребованность на рынке, уровень оплаты, личные приоритеты. Рекомендуется проводить ревизию своих компетенций каждые 3-5 лет.";
    
    if (empty($recommendations)) {
        $recommendations[] = "Для более точного определения карьерного вектора рекомендуется пройти углубленное профориентационное тестирование с психологом.";
    }
    
    return $recommendations;
}

