function calculateModule4Results($responses) {
    $total_score = 0;
    
    foreach ($responses as $answer) {
        $total_score += intval($answer);
    }
    
    $results = [
        'total_score' => $total_score
    ];
    
    if ($total_score <= 13) {
        $results['interpretation'] = 'Низкий риск';
